# Todoの追加関数
def add_todo(todos, task_name):
    new_todo = {"name": task_name, "done": False}
    return todos + [new_todo]

def complete_todo(todos, index):
    updated = todos.copy()
    updated[index] = {**updated[index], "done": True}
    return updated

my_todos = []
my_todos = add_todo(my_todos, "買い物に行く")
my_todos = complete_todo(my_todos, 0)

# 条件分岐でTodoの状態を判定
def get_todo_status(todo):
    if todo["done"]:
        return "完了"
    elif todo.get("priority", 0) >= 4:
        return "緊急"
    else:
        return "未完了"

def filter_todos(todos, show_done):
    if show_done:
        return todos
    else:
        return [t for t in todos if not t["done"]]

# 全Todoを表示する
def display_todos(todos):
    for i, todo in enumerate(todos):
        status = "[x]" if todo["done"] else "[ ]"
        print(f"{i + 1}. {status} {todo['name']}")

def count_done(todos):
    count = 0
    for todo in todos:
        if todo["done"]:
            count += 1
    return count

# イベント処理の概念（CLI版）
def handle_command(command, todos):
    parts = command.split(" ", 1)
    action = parts[0]
    if action == "add":
        return add_todo(todos, parts[1])
    elif action == "done":
        return complete_todo(todos, int(parts[1]) - 1)
    elif action == "list":
        display_todos(todos)
        return todos
    else:
        print("不明なコマンドです")
        return todos

# 状態管理の概念
class TodoApp:
    def __init__(self):
        self._todos = []

    def add(self, task_name):
        self._todos = [*self._todos, {"name": task_name, "done": False}]
        self._render()

    def toggle(self, index):
        todo = self._todos[index]
        updated = {**todo, "done": not todo["done"]}
        self._todos = [updated if i == index else t for i, t in enumerate(self._todos)]
        self._render()

    def _render(self):
        for i, t in enumerate(self._todos):
            s = "[x]" if t["done"] else "[ ]"
            print(f"{i+1}. {s} {t['name']}")
